      const completion = await wait.forToken<{ correctedInput: string }>(waitpoint.id);

      const finalResult = await unreliableTask.triggerAndWait({ 
        input: completion.output.correctedInput, 
        shouldFail: false 
      });

      return finalResult;
    }
  },
});
